const ERROR_OCCURRED_WHILE_LOOKING_FOR = 'An error occurred while looking for';

const getOriginalErrorMessage = (originalError) => `\nError: ${originalError}`;

const getMoreThanOneIslandChildError = (childrenQuantity) =>
  'Island wrapper should have only one child inside but an Island with ' +
  `${childrenQuantity} children exists.`;

const getIslandChildNotExportedError = (name) =>
  `The island child '${name}' should be exported to be used in an islands architecture strategy correctly.`;
const getComponentImportedDynamicallyInsideIslandWrapperError = (name) =>
  `Islands cannot be imported dynamically except using React Lazy, but a dynamic import for the island '${name}' was found.\n` +
  'Please, check Nordic Islands limitations in the following link: ' +
  'https://nordic.adminml.com/docs/nordic-islands/limitations';

const getIslandChildExportedWithCallExpressionError = () =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} default export in file: This component is implemented as an island but it is exported directly wrapped inside a function.\n` +
  'Please, check Nordic Islands limitations in the following link: ' +
  'https://nordic.adminml.com/docs/nordic-islands/limitations';

// TODO: Remove use when "forwardRef" support is removed
/**
 * @param {string} [name]
 */
const getForwardRefIslandWithoutNameError = (name) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} an island: The${name ? ` "${name}"` : ''} component${name ? '' : ' exported as default'}` +
  ' is implemented as an island wrapped with "forwardRef" of React but it has no name.' +
  '\nPlease, check Nordic Islands naming guide: ' +
  'https://nordic.adminml.com/docs/nordic-islands/islands-naming';

// TODO: Remove use when "forwardRef" support is removed
/**
 * @param {string} [name]
 */
const getForwardRefIslandNotDefinedLocallyError = (name) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} an island: The${name ? ` "${name}"` : ''} component${name ? '' : ' exported as default'}` +
  ' is implemented as an island wrapped with "forwardRef" of React but its render function is imported from another file or is not defined as an arrow function.' +
  '\nPlease, check Nordic Islands naming in the following link: ' +
  'https://nordic.adminml.com/docs/nordic-islands/islands-naming#forwardref';

const getLookingForComponentImportError = (componentName, originalError) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} ${componentName} component import inside a component file.\n${originalError}`;

const getIslandChildCallExpressionWithoutDisplaynameError = (name) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} ${name} island information: This island is wrapped with a function and should ` +
  'have a displayName defined.\nPlease, check Nordic Islands naming in the following link: ' +
  'https://nordic.adminml.com/docs/nordic-islands/islands-naming';

const getLookingForComponentPathError = (componentName, originalError) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} ${componentName} component path.${getOriginalErrorMessage(
    originalError,
  )}`;

const getLookingForIslandsAndComponentsError = (originalError) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} islands and components in file.${getOriginalErrorMessage(
    originalError,
  )}`;

const getLookingForIslandsInComponentError = (originalError) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} islands in component.${getOriginalErrorMessage(
    originalError,
  )}`;

const getLookingForIslandsInPageError = (originalError) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} islands in page.${getOriginalErrorMessage(
    originalError,
  )}`;

const getSortingComponentsError = (originalError) =>
  `An error occurred while sorting components of file.${getOriginalErrorMessage(
    originalError,
  )}`;

/**
 * @param {Map<string, string[]>} duplicatedNames
 */
const getIslandsWithDuplicatedNameError = (duplicatedNames) => {
  let message =
    `${ERROR_OCCURRED_WHILE_LOOKING_FOR} islands in the application. ` +
    'Island children should have unique names defined for each one using a named function, named class ' +
    'or the displayName property given by React for components. The duplications found are:';

  duplicatedNames.forEach((files, name) => {
    message += `\n* Name '${name}' used in files:`;

    files.forEach((file) => {
      message += `\n  - ${file}`;
    });
  });

  return message;
};

/**
 * @param {{ importName: string, originPath: string, finalPath: string }} importData
 */
const getIncorrectUseOfESMError = ({ importName, originPath, finalPath }) =>
  `${ERROR_OCCURRED_WHILE_LOOKING_FOR} ${importName} import in file. Make sure of using import/export in a way compatible with ESM.\n` +
  `  Looking from: ${originPath}\n` +
  `  Looking into: ${finalPath}`;

module.exports = {
  getIslandChildNotExportedError,
  getMoreThanOneIslandChildError,
  getComponentImportedDynamicallyInsideIslandWrapperError,
  getLookingForComponentImportError,
  getLookingForComponentPathError,
  getLookingForIslandsAndComponentsError,
  getLookingForIslandsInComponentError,
  getLookingForIslandsInPageError,
  getSortingComponentsError,
  getIslandsWithDuplicatedNameError,
  getIncorrectUseOfESMError,
  getIslandChildExportedWithCallExpressionError,
  getIslandChildCallExpressionWithoutDisplaynameError,
  getForwardRefIslandWithoutNameError,
  getForwardRefIslandNotDefinedLocallyError,
};
